const { exec } = require('child_process');
const { v4: uuidv4 } = require('uuid');
const fs = require('fs');
const path = require('path');

module.exports = async function (context, req) {
    context.log('Document conversion function processed a request.');

    if (!req.body || !req.body.filename || !req.body.outputFormat) {
        context.res = {
            status: 400,
            body: "Please provide filename and outputFormat in the request body."
        };
        return;
    }

    const inputFilename = req.body.filename;
    const outputFormat = req.body.outputFormat;
    
    // Validate output format to prevent command injection
    const allowedFormats = ['pdf', 'docx', 'odt', 'html', 'txt'];
    if (!allowedFormats.includes(outputFormat)) {
        context.res = {
            status: 400,
            body: "Invalid output format. Allowed formats: pdf, docx, odt, html, txt"
        };
        return;
    }

    // Validate input filename to prevent directory traversal
    if (inputFilename.includes('..') || inputFilename.startsWith('/')) {
        context.res = {
            status: 400,
            body: "Invalid filename provided."
        };
        return;
    }

    // Create a secure temporary directory
    const tempDir = path.join('/tmp', `conversion_${uuidv4()}`);
    try {
        fs.mkdirSync(tempDir, { recursive: true });
    } catch (error) {
        context.log.error('Failed to create temp directory:', error);
        context.res = {
            status: 500,
            body: "Internal server error"
        };
        return;
    }

    const inputFile = path.join(tempDir, inputFilename);
    const outputFile = path.join(tempDir, `output.${outputFormat}`);

    // Check if input file exists
    if (!fs.existsSync(inputFile)) {
        context.res = {
            status: 404,
            body: "Input file not found"
        };
        return;
    }

    // Build LibreOffice command with sanitized parameters
    const libreOfficeCommand = `libreoffice --headless --convert-to ${outputFormat} --outdir ${tempDir} ${inputFile}`;

    try {
        const result = await new Promise((resolve, reject) => {
            exec(libreOfficeCommand, { timeout: 30000 }, (error, stdout, stderr) => {
                if (error) {
                    reject(new Error(`Conversion failed: ${stderr || error.message}`));
                } else {
                    resolve({ stdout, stderr });
                }
            });
        });

        // Read the converted file
        const convertedFileBuffer = fs.readFileSync(outputFile);
        
        // Clean up temporary files
        fs.rmSync(tempDir, { recursive: true, force: true });

        context.res = {
            status: 200,
            headers: {
                'Content-Disposition': `attachment; filename="output.${outputFormat}"`,
                'Content-Type': 'application/octet-stream'
            },
            body: convertedFileBuffer
        };
    } catch (error) {
        context.log.error('Conversion error:', error);
        
        // Clean up temporary files on error
        try {
            fs.rmSync(tempDir, { recursive: true, force: true });
        } catch (cleanupError) {
            context.log.error('Cleanup error:', cleanupError);
        }

        context.res = {
            status: 500,
            body: `Conversion failed: ${error.message}`
        };
    }
};